```tsx title="src/App.tsx"
type Member = { name: string; role: string; accent: 'peach' | 'mint' | 'sky' };
type Item = { label: string; meta: string; amount: string };

const household = [
  { name: 'Maya', role: 'Meal prep', accent: 'peach' },
  { name: 'Jon', role: 'Restock', accent: 'mint' },
  { name: 'Ari', role: 'Budget', accent: 'sky' },
] satisfies Member[];

const items = [
  { label: 'Core surface', meta: 'In focus', amount: 'Ready' },
  { label: 'Feature card', meta: 'Weekly', amount: 'Live' },
  { label: 'Launch note', meta: 'Refill', amount: 'Now' },
] satisfies Item[];

const activity = [
  'Use this as the first working pass.',
  'The workspace is ready for iteration.',
  'Turn the starter into the actual product flow.',
];

export default function App() {
  return (
    <main className="shell">
      <section className="hero">
        <p className="eyebrow">client-only image utility app. it should help users turn svgs into high-resolution pngs in two clicks and also make uploaded images square. the first preview must visibly include drag-and-drop upload, svg to png export, scale choices, square crop/padding controls, and a download action.</p>
        <h1>Product Draft</h1>
        <p className="lede">A polished frontend starter shaped directly from the prompt, ready for real features instead of placeholder scaffolding.</p>
      </section>

      <section className="grid">
        <article className="panel">
          <h2>Workspace</h2>
          <div className="members">
            {household.map((member) => (
              <div key={member.name} className={`member member-${member.accent}`}>
                <strong>{member.name}</strong>
                <span>{member.role}</span>
              </div>
            ))}
          </div>
        </article>

        <article className="panel">
          <h2>Highlights</h2>
          <div className="cards">
            {items.map((item) => (
              <div key={item.label} className="card">
                <span>{item.meta}</span>
                <strong>{item.label}</strong>
                <em>{item.amount}</em>
              </div>
            ))}
          </div>
        </article>

        <article className="panel">
          <h2>Recent Activity</h2>
          <ul className="activity">
            {activity.map((entry) => (
              <li key={entry}>{entry}</li>
            ))}
          </ul>
        </article>
      </section>
    </main>
  );
}
```

